async function main() {
  console.log('🏛️  Seeding 30 museums, libraries & gardens...')
  for (const p of places) {
    const s = slug(p.name)
    await prisma.place.upsert({ where: { slug: s }, update: {}, create: { ...p, slug: s } })
    console.log('  ✅', p.name)
  }
  console.log('🏛️  Done!')
}

main().catch(e => { console.error(e); process.exit(1) }).finally(() => prisma.$disconnect())
